-- JSONB with GIN index (richer than Cassandra map<text,text>)
CREATE TABLE tech_docs (
  id        UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  metadata  JSONB NOT NULL,
  embedding vector(384)
);

CREATE INDEX idx_meta_gin  ON tech_docs USING GIN (metadata);
CREATE INDEX idx_vec_hnsw  ON tech_docs USING hnsw (embedding vector_cosine_ops);

-- Filter by JSONB field + nearest-neighbor vector search in one query
SELECT id, metadata->>'title' AS title
FROM   tech_docs
WHERE  metadata @> '{"lang": "python"}'
ORDER  BY embedding <=> '[0.12, 0.87, ...]'::vector
LIMIT  5;

from elasticsearch import Elasticsearch

es = Elasticsearch("http://localhost:9200")

es.indices.create(index="tech_events", body={
    "mappings": {
        "properties": {
            "event_id":  {"type": "keyword"},
            "payload":   {"type": "text", "analyzer": "english"},
            "timestamp": {"type": "date"},
            "severity":  {"type": "keyword"}
        }
    }
})

# Sync a Cassandra row into ES
es.index(index="tech_events", id="abc-123", document={
    "event_id": "abc-123",
    "payload": "Cassandra compaction triggered on dc1-node3",
    "timestamp": "2026-04-16T10:00:00Z",
    "severity": "warn"
})

# Bool query + bucket aggregation — no CQL equivalent
result = es.search(index="tech_events", body={
    "query": {
        "bool": {
            "must":   {"match":  {"payload": "compaction"}},
            "filter": {"term":   {"severity": "warn"}}
        }
    },
    "aggs": {
        "by_severity": {"terms": {"field": "severity"}}
    }
})

-- Enable tracing in cqlsh
TRACING ON;

SELECT * FROM events WHERE user_id = 'abc-123';
-- Output includes: sstables touched, tombstones scanned, read latency per stage

TRACING OFF;

-- N+1 anti-pattern
-- BAD: loop of individual reads per partition key
-- SELECT * FROM events WHERE user_id = ?;  -- called 100x in application code

-- GOOD: single fan-out read
SELECT event_id, event_type, created_at
FROM events
WHERE user_id IN ('abc-123', 'def-456', 'ghi-789');

-- RF=3 keyspace across two DCs
CREATE KEYSPACE orders
  WITH replication = {
    'class': 'NetworkTopologyStrategy',
    'us-east': 3,
    'eu-west': 3
  };

-- Strong consistency write + read within local DC
INSERT INTO orders.events (id, payload) VALUES (uuid(), 'checkout')
USING CONSISTENCY LOCAL_QUORUM;

SELECT * FROM orders.events WHERE id = ?
USING CONSISTENCY LOCAL_QUORUM;

-- Enable auth in cassandra.yaml first, then:
CREATE ROLE app_reader WITH PASSWORD = 'str0ng!' AND LOGIN = TRUE;
CREATE ROLE app_writer WITH PASSWORD = 'wr1te!' AND LOGIN = TRUE;

-- Least privilege: reader gets SELECT only on one table
GRANT SELECT ON TABLE analytics.events TO app_reader;

-- Writer gets DML but NOT DDL
GRANT MODIFY ON TABLE analytics.events TO app_writer;
GRANT SELECT ON TABLE analytics.events TO app_writer;

-- Revoke all rights from the default superuser in prod
ALTER ROLE cassandra WITH PASSWORD = 'rotated-and-vaulted' AND SUPERUSER = FALSE;

-- 1. Verify schema agreement before any DDL
--    nodetool describecluster | grep 'Schema versions'
--    Must show exactly ONE UUID. If two appear, wait for gossip convergence.

-- 2. Safe additive migration (non-blocking, gossip-propagated)
ALTER TABLE user_events ADD metadata map<text, text>;

-- 3. Dual-write pattern: introduce new column alongside old
ALTER TABLE user_events ADD event_source_v2 varchar;

-- 4. After DSBulk backfill + full app cutover to event_source_v2:
--    Wait gc_grace_seconds (default 864000s / 10 days), then:
ALTER TABLE user_events DROP event_source;
